export declare function getBidFillAmount(auctionBucket: Pick<AuctionBucketV1Input, 'clearingPriceBidNumber' | 'clearingPriceAllocation'>, bid: Pick<BidInput, 'bidNumber' | 'tokenQuantity'>): bigint;
